#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e5+5;
struct SegT{
    int x,y,c1,mxlen;
}t[N<<2];
int n,Q,dep[N],f[N][20];
int Fa[N],sz[N],wc[N],top[N];
int Cnt,dfn[N],fd[N];
vector<int> g[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS1(int u,int fa){
    Fa[u]=fa,sz[u]=1;
    dep[u]=dep[fa]+1;
    for(int v:g[u])if(v^fa){
        DFS1(v,u),sz[u]+=sz[v];
        if(sz[v]>sz[wc[u]])wc[u]=v;
    }return;
}
void DFS2(int u,int Top){
    top[u]=Top;
    dfn[u]=(++Cnt),fd[Cnt]=u;
    if(wc[u])DFS2(wc[u],Top);
    for(int v:g[u])
        if(v^Fa[u]&&v^wc[u])DFS2(v,v);return;
}
int LCA(int x,int y){
    while(top[x]!=top[y]){
        if(dfn[top[x]]<dfn[top[y]])swap(x,y);
        x=Fa[top[x]];
    }if(dfn[x]>dfn[y])swap(x,y);
    return x;
}
int dis(int u,int v){
    return dep[u]+dep[v]-2*dep[LCA(u,v)];
}
SegT operator + (const SegT &A , const SegT &B){
    if(!A.c1)return B;
    if(!B.c1)return A;
    SegT C;C.c1=A.c1+B.c1;
    int a=A.x,b=A.y,c=B.x,d=B.y;
    int rx=0,ry=0,res=0;
    if(dis(a,b)>res)res=dis(a,b),rx=a,ry=b;
    if(dis(a,c)>res)res=dis(a,c),rx=a,ry=c;
    if(dis(a,d)>res)res=dis(a,d),rx=a,ry=d;
    if(dis(b,c)>res)res=dis(b,c),rx=b,ry=c;
    if(dis(b,d)>res)res=dis(b,d),rx=b,ry=d;
    if(dis(c,d)>res)res=dis(c,d),rx=c,ry=d;
    C.x=rx,C.y=ry,C.mxlen=res;
    return C;
}
int ls(int u){return (u<<1);}
int rs(int u){return (u<<1|1);}
void push_up(int u){
    t[u]=t[ls(u)]+t[rs(u)];return;
}
void build(int u,int l,int r){
    if(l==r){t[u]={l,l,1,0};return;}
    int mid=(l+r)>>1;
    build(ls(u),l,mid);build(rs(u),mid+1,r);
    push_up(u);return;
}
void change(int u,int l,int r,int LR){
    if(l==r&&l==LR){t[u].c1=1-t[u].c1;return;}
    int mid=(l+r)>>1;
    if(LR<=mid)change(ls(u),l,mid,LR);
    else change(rs(u),mid+1,r,LR);
    push_up(u);return;
}
int main(){
    n=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }DFS1(1,0),DFS2(1,0);
    build(1,1,n);
    Q=read();
    while(Q--){
        char opt;cin>>opt;
        if(opt=='C'){
            int x=read();
            change(1,1,n,x);
        }else{
            if(!t[1].c1)cout<<"-1\n";
            else cout<<t[1].mxlen<<"\n";
        }
    }
    return 0;
}
